<script setup lang="ts">import { checkFeature, expansionFeature, selectionFeature } from '@fex/components-core'; import { createTreeController } from '@fex/components-core/tree/create-tree-controller'; import type { CheckFeatureApi } from '@fex/components-core/tree/features/check'; import type { ExpansionFeatureApi } from '@fex/components-core/tree/features/expansion'; import type { SelectionFeatureApi } from '@fex/components-core/tree/features/selection'; import Button from '@fex/components-vue/ui/button'; import Card from '@fex/components-vue/ui/card'; import DemoTree from './demo-tree.vue'; import { departmentFieldNames,departmentTreeData,type DepartmentNode } from './data'; const controller=createTreeController<DepartmentNode>({treeData:departmentTreeData,fieldNames:departmentFieldNames,isLeaf:n=>n.childCount===0,features:[expansionFeature(),selectionFeature({multiple:true}),checkFeature()]})</script>
<template><Card title="Controller batch actions" description="All batch operations are explicit controller actions. selectAll only acts when multiple selection is enabled."><div class="mb-space-md flex flex-wrap gap-space-sm"><Button size="sm" variant="outline" @click="controller.getFeature<ExpansionFeatureApi>('expansion')?.expandAll()">Expand all</Button><Button size="sm" variant="outline" @click="controller.getFeature<ExpansionFeatureApi>('expansion')?.collapseAll()">Collapse all</Button><Button size="sm" variant="outline" @click="controller.getFeature<SelectionFeatureApi>('selection')?.selectAll()">Select all</Button><Button size="sm" variant="outline" @click="controller.getFeature<SelectionFeatureApi>('selection')?.clear()">Clear selection</Button><Button size="sm" variant="outline" @click="controller.getFeature<CheckFeatureApi>('check')?.checkAll()">Check all</Button><Button size="sm" variant="outline" @click="controller.getFeature<CheckFeatureApi>('check')?.clear()">Clear checks</Button></div><DemoTree :controller="controller" :tree-data="departmentTreeData" :field-names="departmentFieldNames" :is-leaf="node=>node.childCount===0" checkable class="max-w-xl rounded-md border border-border bg-background p-space-sm" /></Card></template>
